 90→function findPortraitSequenceIndex(model: ModelType): number {
 91→  const sequences = model.Sequences || [];
 92→  if (sequences.length === 0) return 0;
 93→  const byName = (predicate: (name: string) => boolean) =>
 94→    sequences.findIndex((seq) => predicate((seq.Name || '').toLowerCase()));
 95→  let idx = byName((name) => name.includes('portrait') && !name.includes('talk'));
 96→  if (idx >= 0) return idx;
 97→  idx = byName((name) => name.includes('stand'));
 98→  if (idx >= 0) return idx;
 99→  idx = byName((name) => name.includes('portrait'));
100→  if (idx >= 0) return idx;
101→  return 0;
102→}
