12→/** Validate and add builds, returning the count of successfully imported entries. */
13→export function importBuilds(data: unknown): number {
14→  if (!Array.isArray(data)) {
15→    // Allow a single object wrapped as an array
16→    if (data && typeof data === "object" && "steps" in data) {
17→      data = [data];
18→    } else {
19→      return 0;
20→    }
21→  }
22→
23→  const valid: BuildOrder[] = [];
24→  for (const item of data as unknown[]) {
25→    if (!item || typeof item !== "object") continue;
26→    const obj = item as Record<string, unknown>;
27→
28→    if (typeof obj.name !== "string" || !obj.name) continue;
29→    if (typeof obj.race !== "string" || !VALID_RACES.has(obj.race)) continue;
30→    if (!Array.isArray(obj.steps) || obj.steps.length === 0) continue;
31→
32→    const steps: { order: number; time: string; instruction: string; food: string }[] = [];
33→    let stepsOk = true;
34→    for (const s of obj.steps) {
35→      if (!s || typeof s !== "object") { stepsOk = false; break; }
36→      const st = s as Record<string, unknown>;
37→      if (typeof st.order !== "number") { stepsOk = false; break; }
38→      if (typeof st.time !== "string") { stepsOk = false; break; }
39→      if (typeof st.instruction !== "string") { stepsOk = false; break; }
40→      if (typeof st.food !== "string") { stepsOk = false; break; }
41→      steps.push({
42→        order: st.order,
43→        time: st.time,
44→        instruction: st.instruction,
45→        food: st.food,
46→      });
47→    }
48→    if (!stepsOk) continue;
49→
50→    valid.push({
51→      name: obj.name,
52→      race: obj.race,
53→      description: typeof obj.description === "string" ? obj.description : "",
54→      vs: typeof obj.vs === "string" ? obj.vs : undefined,
55→      difficulty:
56→        obj.difficulty === "Beginner" ||
57→        obj.difficulty === "Intermediate" ||
58→        obj.difficulty === "Advanced"
59→          ? obj.difficulty
60→          : undefined,
61→      keyTiming:
62→        obj.keyTiming &&
63→        typeof obj.keyTiming === "object" &&
64→        typeof (obj.keyTiming as Record<string, unknown>).minute === "number" &&
65→        typeof (obj.keyTiming as Record<string, unknown>).note === "string"
66→          ? (obj.keyTiming as { minute: number; note: string })
67→          : undefined,
68→      note: typeof obj.note === "string" ? obj.note : undefined,
69→      steps,
70→    });
71→  }
72→
73→  if (valid.length === 0) return 0;
74→
75→  store.set((prev) => [...prev, ...valid]);
76→  return valid.length;
77→}
